#!/usr/bin/env python3
# post — append a message to the wall. argv: <author> <text...>. One arg = anon.
import sys, json
a = sys.argv[1:]
if len(a) == 0:
    author, text = "anon", ""
elif len(a) == 1:
    author, text = "anon", a[0]
else:
    author, text = a[0], " ".join(a[1:])
print(json.dumps({"name": "wall.posted", "payload": {"author": author, "text": text}}))
